import{_ as a,o as e,c as r,ak as s}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"STAR 法则：如何描述项目经历","description":"","frontmatter":{},"headers":[],"relativePath":"interview/resume/star.md","filePath":"interview/resume/star.md","lastUpdated":1774284433000}'),i={name:"interview/resume/star.md"};function o(l,t,n,d,h,p){return e(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="star-法则-如何描述项目经历" tabindex="-1">STAR 法则：如何描述项目经历 <a class="header-anchor" href="#star-法则-如何描述项目经历" aria-label="Permalink to “STAR 法则：如何描述项目经历”">​</a></h1><blockquote><p>STAR 法则不只是面试答题框架，更是写简历项目描述的最佳武器。</p></blockquote><h2 id="什么是-star-法则" tabindex="-1">什么是 STAR 法则 <a class="header-anchor" href="#什么是-star-法则" aria-label="Permalink to “什么是 STAR 法则”">​</a></h2><p>STAR 是四个英文单词的首字母缩写：</p><table tabindex="0"><thead><tr><th>字母</th><th>含义</th><th>说明</th></tr></thead><tbody><tr><td><strong>S</strong></td><td>Situation</td><td>背景：项目在什么场景下启动</td></tr><tr><td><strong>T</strong></td><td>Task</td><td>任务：你的职责是什么，负责什么模块</td></tr><tr><td><strong>A</strong></td><td>Action</td><td>行动：你具体做了什么，采用什么技术方案</td></tr><tr><td><strong>R</strong></td><td>Result</td><td>结果：最终带来了什么效果（最好量化）</td></tr></tbody></table><p><strong>核心逻辑</strong>：先让人理解「为什么做」，再说明「做了什么」，最后展示「做成了什么」。</p><h2 id="简历-vs-面试-用法的微妙区别" tabindex="-1">简历 vs 面试：用法的微妙区别 <a class="header-anchor" href="#简历-vs-面试-用法的微妙区别" aria-label="Permalink to “简历 vs 面试：用法的微妙区别”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>用法重点</th></tr></thead><tbody><tr><td>简历</td><td>重点在 <strong>A（行动）</strong> 和 <strong>R（结果）</strong>，S 和 T 压缩到一句话</td></tr><tr><td>面试</td><td>四步完整展开，尤其是 T 和 A，要引导到自己的核心贡献</td></tr></tbody></table><h2 id="简历写法-精简版-star" tabindex="-1">简历写法：精简版 STAR <a class="header-anchor" href="#简历写法-精简版-star" aria-label="Permalink to “简历写法：精简版 STAR”">​</a></h2><p>简历空间有限，要用最少的字传达最多的信息。</p><h3 id="对比-不用-star-vs-用-star" tabindex="-1">对比：不用 STAR vs 用 STAR <a class="header-anchor" href="#对比-不用-star-vs-用-star" aria-label="Permalink to “对比：不用 STAR vs 用 STAR”">​</a></h3><p><strong>不用 STAR（流水账）：</strong></p><blockquote><p>在项目中负责用户模块的开发，使用 Redis 做缓存，使用 MQ 做消息通知。</p></blockquote><p><strong>用 STAR（精简版）：</strong></p><blockquote><p>针对高并发场景下用户查询热点问题，设计并实现了多级缓存方案（本地缓存 + Redis 分布式缓存）， 配合缓存预热与异步刷新机制，使接口 QPS 从 1200 提升至 8500，P99 延迟从 180ms 降至 28ms。</p></blockquote><p>对比非常明显：第二个版本不仅说清楚了做什么，还量化了价值。</p><h3 id="模板" tabindex="-1">模板 <a class="header-anchor" href="#模板" aria-label="Permalink to “模板”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>【动词】+ 【具体工作内容】+ 【用了什么技术/方案】+ 【带来了什么量化结果】</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>常见动词：</p><ul><li><strong>设计</strong>：<code>设计了 XX 方案，解决了 XX 问题</code></li><li><strong>实现</strong>：<code>实现了 XX 功能，支持 XX 规模</code></li><li><strong>优化</strong>：<code>优化了 XX 指标，从 XX 降低/提升到 XX</code></li><li><strong>重构</strong>：<code>重构了 XX 模块，代码行数减少 XX%，可维护性提升</code></li><li><strong>引入</strong>：<code>引入了 XX 技术栈，解决了 XX 痛点</code></li><li><strong>主导</strong>：<code>主导了 XX 项目，跨团队协调 XX 人</code></li></ul><h2 id="面试口头表达-完整版-star" tabindex="-1">面试口头表达：完整版 STAR <a class="header-anchor" href="#面试口头表达-完整版-star" aria-label="Permalink to “面试口头表达：完整版 STAR”">​</a></h2><p>面试中回答项目问题时，STAR 四个维度都要展开。</p><h3 id="范例-如何回答「介绍一个你做过的有挑战的项目」" tabindex="-1">范例：如何回答「介绍一个你做过的有挑战的项目」 <a class="header-anchor" href="#范例-如何回答「介绍一个你做过的有挑战的项目」" aria-label="Permalink to “范例：如何回答「介绍一个你做过的有挑战的项目」”">​</a></h3><p><strong>S（背景）：</strong></p><blockquote><p>我们公司当时日均订单量大概 30 万，峰值 QPS 能到 5000 左右。但订单确认接口的平均响应时间是 200ms，99 线更是到了 800ms，用户投诉比较多。</p></blockquote><p><strong>T（任务）：</strong></p><blockquote><p>我作为后端负责人，承接了这个接口性能优化的任务，目标是把它优化到 50ms 以内。</p></blockquote><p><strong>A（行动）：</strong></p><blockquote><p>我首先做了性能分析，用 Arthas 定位到瓶颈在数据库查询，单次请求平均触发了 8 次数据库 IO，其中有个关联查询耗了 100ms。</p><p>确定了瓶颈之后，我做了三件事：</p><p>第一，对高频查询加了 Redis 缓存，设置 5 分钟 TTL，预热了 Top 100 热数据；</p><p>第二，把那个慢查询拆成了两步简单的查询，用并行请求合并结果；</p><p>第三，对非核心的库存校验消息做了异步化，用 RocketMQ 解耦。</p><p>改完之后又做了一轮全链路压测，在 8000 QPS 的情况下验证了稳定性。</p></blockquote><p><strong>R（结果）：</strong></p><blockquote><p>最终接口 P50 降到了 18ms，P99 降到了 45ms，达到了目标。另外这个缓存方案后来被推广到了用户模块和商品模块，整体接口 RT 降低了 60%。</p></blockquote><h2 id="常见问题与注意事项" tabindex="-1">常见问题与注意事项 <a class="header-anchor" href="#常见问题与注意事项" aria-label="Permalink to “常见问题与注意事项”">​</a></h2><h3 id="q-项目经历太多了-怎么选" tabindex="-1">Q：项目经历太多了，怎么选？ <a class="header-anchor" href="#q-项目经历太多了-怎么选" aria-label="Permalink to “Q：项目经历太多了，怎么选？”">​</a></h3><p>选择标准按这个优先级：</p><ol><li><strong>技术有深度</strong>：涉及原理、源码、设计模式</li><li><strong>规模有量级</strong>：数据量大、高并发、分布式</li><li><strong>结果有量化</strong>：性能提升、成本降低、效率提升</li><li><strong>个人有贡献</strong>：是你主导或核心参与，而不是打酱油</li></ol><h3 id="q-结果不好怎么办" tabindex="-1">Q：结果不好怎么办？ <a class="header-anchor" href="#q-结果不好怎么办" aria-label="Permalink to “Q：结果不好怎么办？”">​</a></h3><p>很多项目的结果可能不理想，比如系统最终没做起来。这种情况：</p><ul><li>可以换角度讲：「虽然项目因为 XX 原因暂停了，但我在 XX 方面的设计经验对后续项目很有帮助」</li><li>或者讲过程中的学习：「通过这个项目我深入理解了 XX，为后续 XX 项目打下了基础」</li></ul><h3 id="q-团队合作的项目怎么写" tabindex="-1">Q：团队合作的项目怎么写？ <a class="header-anchor" href="#q-团队合作的项目怎么写" aria-label="Permalink to “Q：团队合作的项目怎么写？”">​</a></h3><p>明确区分「我做了什么」和「团队做了什么」：</p><blockquote><ul><li>负责用户下单模块，基于 Spring Cloud 实现，QPS 支撑 5000+</li><li>团队其他同学负责商品模块和支付模块</li></ul></blockquote><p>不要把团队成果全归功于自己，也不要完全不提自己的贡献。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>STAR 法则的核心心法：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>好的项目描述 = S（让人相信这件事值得做）+ A（让人看到你的能力）+ R（让人记住你的价值）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>写简历时，重点练三个动作：</p><ol><li>每个项目总结出 <strong>1-2 个量化数据</strong></li><li>每个数据背后有 <strong>1 句话的技术方案说明</strong></li><li>准备 <strong>2-3 个深度追问的答案</strong>（面试时会问）</li></ol>',47)])])}const g=a(i,[["render",o]]);export{b as __pageData,g as default};
